'use client'

interface UseProductActionsReturn {
  addSupplement: (productId: string) => Promise<void>
  addFavorite: (productId: string) => Promise<void>
}

export function useProductActions(): UseProductActionsReturn {
  const addSupplement = async (productId: string) => {
    try {
      const res = await fetch('/api/my/supplements', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ product_id: productId }),
      })
      if (res.ok) {
        alert('내 영양제에 등록되었습니다.')
      } else {
        const data = await res.json()
        alert(data.error?.message || '등록에 실패했습니다.')
      }
    } catch {
      alert('등록에 실패했습니다.')
    }
  }

  const addFavorite = async (productId: string) => {
    try {
      const res = await fetch('/api/my/favorites', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ product_id: productId }),
      })
      if (res.ok) {
        alert('즐겨찾기에 추가되었습니다.')
      } else {
        const data = await res.json()
        alert(data.error?.message || '추가에 실패했습니다.')
      }
    } catch {
      alert('추가에 실패했습니다.')
    }
  }

  return { addSupplement, addFavorite }
}
